    )

mapper.update:
UPDATE contractpartnermatchings
   SET mcp_contractpartnerid = #{mcpContractpartnerId}
     , matching_text         = #{matchingText}
     , mmf_comment           = #{mmfComment}
     , mpa_postingaccountid  = #{mpaPostingAccountId}
 WHERE contractpartnermatchingid = #{id}

UPDATE contractpartnermatchings
